import { useMemo, useState } from 'react';

import type { Campaign } from '@/features/campaigns/types/campaign.types';
import { useCampaignActions } from '@/features/campaigns/hooks/useCampaignActions';
import { Button } from '@/shared/components/ui/Button';
import { ErrorMessage } from '@/shared/components/ui/ErrorMessage';
import { Input } from '@/shared/components/ui/Input';
import { StatusMessage } from '@/shared/components/ui/StatusMessage';

type CampaignActionsProps = {
  campaign: Campaign;
};

export function CampaignActions({ campaign }: CampaignActionsProps) {
  const { isLoading, actionError, actionSuccess, onDelete, onScheduleAt, onSendNow, canDelete, canSchedule, canSend } =
    useCampaignActions(campaign);
  const minScheduleValue = useMemo(() => {
    const now = new Date(Date.now() + 60_000);
    now.setSeconds(0, 0);
    const timezoneOffsetMinutes = now.getTimezoneOffset();
    const localDate = new Date(now.getTime() - timezoneOffsetMinutes * 60 * 1000);
    return localDate.toISOString().slice(0, 16);
  }, []);
  const defaultScheduleValue = useMemo(() => {
    const source =
      campaign.scheduled_at && new Date(campaign.scheduled_at).getTime() > Date.now()
        ? new Date(campaign.scheduled_at)
        : new Date(Date.now() + 15 * 60 * 1000);
    source.setSeconds(0, 0);
    const timezoneOffsetMinutes = source.getTimezoneOffset();
    const localDate = new Date(source.getTime() - timezoneOffsetMinutes * 60 * 1000);
    return localDate.toISOString().slice(0, 16);
  }, [campaign.scheduled_at]);
  const [scheduledAtLocal, setScheduledAtLocal] = useState(defaultScheduleValue);
  const timezoneLabel = Intl.DateTimeFormat().resolvedOptions().timeZone;
  const scheduleButtonLabel = campaign.status === 'scheduled' ? 'Reschedule' : 'Schedule';
  const scheduleInputLabel = campaign.status === 'scheduled' ? 'Reschedule time' : 'Schedule time';

  return (
    <section className="space-y-3 rounded-lg bg-white p-4 shadow">
      <h3 className="text-base font-semibold">Actions</h3>
      {canSchedule ? (
        <div className="space-y-2">
          <label className="block text-sm font-medium">{scheduleInputLabel}</label>
          <Input
            type="datetime-local"
            value={scheduledAtLocal}
            onChange={(event) => setScheduledAtLocal(event.target.value)}
            min={minScheduleValue}
            disabled={isLoading}
          />
          <p className="text-xs text-slate-500">Time zone: {timezoneLabel}. It will be converted to UTC when sent.</p>
        </div>
      ) : null}
      <div className="flex flex-wrap gap-2">
        {canSchedule ? (
          <Button variant="outline" disabled={isLoading} onClick={() => void onScheduleAt(scheduledAtLocal)}>
            {scheduleButtonLabel}
          </Button>
        ) : null}
        {canSend ? (
          <Button disabled={isLoading} onClick={() => void onSendNow()}>
            Send
          </Button>
        ) : null}
        {canDelete ? (
          <Button variant="danger" disabled={isLoading} onClick={() => void onDelete()}>
            Delete
          </Button>
        ) : null}
      </div>
      <StatusMessage type="success" message={actionSuccess} />
      <ErrorMessage message={actionError} />
    </section>
  );
}
